const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const mongoSanitize = require('express-mongo-sanitize');

const app = express();

// ===== SECURITY MIDDLEWARE =====

// 1. Set security HTTP headers
app.use(helmet());

// 2. Body parser with size limits
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ limit: '10kb', extended: true }));

// 3. Data sanitization against NoSQL injection
app.use(mongoSanitize());

// 4. Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // limit each IP to 100 requests per windowMs
  message: 'Too many requests from this IP, please try again later.',
  standardHeaders: true,
  legacyHeaders: false,
});
app.use('/api/', limiter);

// 5. Health check endpoint (less strict rate limit)
const healthLimiter = rateLimit({
  windowMs: 60 * 1000,
  max: 30,
});
app.use('/health', healthLimiter);

// ===== VALIDATION HELPER =====
const validateQueryParams = (req, res, next) => {
  const allowedParams = ['page', 'limit', 'sort'];
  const providedParams = Object.keys(req.query);

  for (const param of providedParams) {
    if (!allowedParams.includes(param)) {
      return res.status(400).json({
        error: 'Invalid query parameter',
        param: param
      });
    }
  }

  // Validate numeric values
  if (req.query.page && (isNaN(req.query.page) || req.query.page < 1)) {
    return res.status(400).json({ error: 'Invalid page number' });
  }

  if (req.query.limit && (isNaN(req.query.limit) || req.query.limit < 1 || req.query.limit > 100)) {
    return res.status(400).json({ error: 'Limit must be between 1 and 100' });
  }

  next();
};

// ===== ROUTES =====

app.get('/health', (req, res) => {
  try {
    res.json({ 
      status: 'ok', 
      timestamp: new Date().toISOString(),
      uptime: process.uptime()
    });
  } catch (error) {
    console.error('Health check error:', error);
    res.status(500).json({ status: 'error' });
  }
});

app.get('/users', validateQueryParams, (req, res) => {
  try {
    // Mock data - in production, fetch from secure database
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // Apply pagination
    const page = parseInt(req.query.page) || 1;
    const limit = Math.min(parseInt(req.query.limit) || 10, 100);
    const start = (page - 1) * limit;
    const paginatedUsers = users.slice(start, start + limit);

    res.json({
      data: paginatedUsers,
      page,
      limit,
      total: users.length
    });
  } catch (error) {
    console.error('Error fetching users:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

// ===== ERROR HANDLING =====

// 404 handler
app.use((req, res) => {
  res.status(404).json({ error: 'Route not found' });
});

// Global error handler
app.use((err, req, res, next) => {
  console.error('Unhandled error:', {
    message: err.message,
    stack: err.stack,
    timestamp: new Date().toISOString()
  });

  res.status(err.status || 500).json({
    error: process.env.NODE_ENV === 'production' 
      ? 'Internal server error' 
      : err.message
  });
});

// ===== SERVER START =====
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;
```

